  `unit_price` decimal(12,2) NOT NULL,
  `received_quantity` decimal(12,3) NOT NULL,
  `conversion_factor` decimal(12,3) NOT NULL DEFAULT (1.000),
  PRIMARY KEY (`id`),
  KEY `purchase_order_id` (`purchase_order_id`),
  KEY `raw_material_id` (`raw_material_id`),
