DROP TABLE IF EXISTS `raw_materials`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `raw_materials` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(150) NOT NULL,
  `unit_id` int NOT NULL,
  `waste_percentage` decimal(5,2) NOT NULL,
  `stock` decimal(12,3) NOT NULL,
  `description` text,
  `status` varchar(20) NOT NULL,
  `category_id` int NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deactivated_at` datetime DEFAULT NULL,
  `created_by` int DEFAULT NULL,
  `updated_by` int DEFAULT NULL,
  `deactivated_by` int DEFAULT NULL,
  `minimum_stock` decimal(12,3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `name` (`name`),
  KEY `unit_id` (`unit_id`),
  KEY `category_id` (`category_id`),
  KEY `created_by` (`created_by`),
  KEY `deactivated_by` (`deactivated_by`),
  KEY `updated_by` (`updated_by`),
  CONSTRAINT `raw_materials_ibfk_1` FOREIGN KEY (`unit_id`) REFERENCES `units` (`id`),
  CONSTRAINT `raw_materials_ibfk_3` FOREIGN KEY (`category_id`) REFERENCES `material_categories` (`id`),
  CONSTRAINT `raw_materials_ibfk_4` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `raw_materials_ibfk_5` FOREIGN KEY (`deactivated_by`) REFERENCES `users` (`id`),
  CONSTRAINT `raw_materials_ibfk_6` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=34 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
